class_name XiangqiBoard
extends Node2D

# 中国象棋棋盘常量
const BOARD_WIDTH = 9   # 9列
const BOARD_HEIGHT = 10 # 10行
const CELL_SIZE = 60    # 格子大小

# 棋盘位置偏移
var board_offset: Vector2 = Vector2(100, 50)

# 当前棋盘状态: null 或棋子对象
var grid: Array = []

# 信号
signal piece_moved(from_pos, to_pos, piece)
signal piece_captured(attacker, target)

func _ready():
	_init_board()

func _init_board():
	# 初始化空棋盘
	grid = []
	for x in range(BOARD_WIDTH):
		grid.append([])
		for y in range(BOARD_HEIGHT):
			grid[x].append(null)

# 世界坐标转棋盘坐标
func world_to_grid(world_pos: Vector2) -> Vector2i:
	var relative = world_pos - board_offset
	var x = round(relative.x / CELL_SIZE)
	var y = round(relative.y / CELL_SIZE)
	return Vector2i(x, y)

# 棋盘坐标转世界坐标
func grid_to_world(grid_pos: Vector2i) -> Vector2:
	return board_offset + Vector2(grid_pos.x * CELL_SIZE, grid_pos.y * CELL_SIZE)

# 检查坐标是否在棋盘内
func is_valid_position(pos: Vector2i) -> bool:
	return pos.x >= 0 and pos.x < BOARD_WIDTH and pos.y >= 0 and pos.y < BOARD_HEIGHT

# 获取格子上的棋子
func get_piece_at(pos: Vector2i) -> Piece:
	if not is_valid_position(pos):
		return null
	return grid[pos.x][pos.y]

# 放置棋子
func place_piece(piece: Piece, pos: Vector2i):
	if is_valid_position(pos):
		grid[pos.x][pos.y] = piece
		if piece:
			piece.board_pos = pos
			piece.position = grid_to_world(pos)

# 移动棋子
func move_piece(from_pos: Vector2i, to_pos: Vector2i) -> bool:
	var piece = get_piece_at(from_pos)
	if not piece:
		return false

	var target = get_piece_at(to_pos)

	# 更新网格
	grid[from_pos.x][from_pos.y] = null
	grid[to_pos.x][to_pos.y] = piece

	# 更新棋子位置
	piece.board_pos = to_pos

	# 动画移动
	var tween = create_tween()
	tween.tween_property(piece, "position", grid_to_world(to_pos), 0.2)

	if target:
		target.queue_free()
		piece_captured.emit(piece, target)

	piece_moved.emit(from_pos, to_pos, piece)
	return true

# 验证马的走法（日字）
func is_valid_horse_move(from_pos: Vector2i, to_pos: Vector2i) -> bool:
	var dx = abs(to_pos.x - from_pos.x)
	var dy = abs(to_pos.y - from_pos.y)

	# 马走日：必须是 2+1 或 1+2
	if not ((dx == 2 and dy == 1) or (dx == 1 and dy == 2)):
		return false

	# 检查绊马脚
	var blocking_pos: Vector2i
	if dx == 2:
		# 横向移动2格，检查横向中间的格子
		blocking_pos = Vector2i((from_pos.x + to_pos.x) / 2, from_pos.y)
	else:
		# 纵向移动2格，检查纵向中间的格子
		blocking_pos = Vector2i(from_pos.x, (from_pos.y + to_pos.y) / 2)

	if get_piece_at(blocking_pos) != null:
		return false  # 有棋子绊马脚

	return true

# 获取马的所有合法走法
func get_horse_valid_moves(pos: Vector2i) -> Array[Vector2i]:
	var moves: Array[Vector2i] = []
	var horse_moves = [
		Vector2i(2, 1), Vector2i(2, -1),
		Vector2i(-2, 1), Vector2i(-2, -1),
		Vector2i(1, 2), Vector2i(1, -2),
		Vector2i(-1, 2), Vector2i(-1, -2)
	]

	for move in horse_moves:
		var target = pos + move
		if is_valid_position(target) and is_valid_horse_move(pos, target):
			moves.append(target)

	return moves

func _draw():
	# 绘制棋盘背景
	draw_rect(Rect2(board_offset - Vector2(5, 5), 
		Vector2(BOARD_WIDTH * CELL_SIZE + 10, BOARD_HEIGHT * CELL_SIZE + 10)), 
		Color(0.9, 0.7, 0.4), true)

	# 绘制格子线
	for x in range(BOARD_WIDTH):
		for y in range(BOARD_HEIGHT):
			var pos = grid_to_world(Vector2i(x, y))
			draw_rect(Rect2(pos - Vector2(CELL_SIZE/2, CELL_SIZE/2), 
				Vector2(CELL_SIZE, CELL_SIZE)), 
				Color(0.85, 0.65, 0.35), false, 1)

class_name Piece
extends Node2D

enum Type { HORSE, CHARIOT, CANNON, ELEPHANT, ADVISOR, GENERAL, SOLDIER }
enum Side { RED, BLACK }

@export var piece_type: Type = Type.HORSE
@export var side: Side = Side.RED
@export var piece_name: String = "马"

var board_pos: Vector2i = Vector2i.ZERO
var is_selected: bool = false

@onready var sprite: Polygon2D = $Polygon2D

func _ready():
	_draw_piece()

func _draw_piece():
	# 使用 Polygon2D 绘制简单棋子
	# 实际项目中替换为图片
	var color = Color.RED if side == Side.RED else Color.BLACK

	# 绘制圆形棋子底
	var circle_points = []
	for i in range(32):
		var angle = i * PI / 16
		circle_points.append(Vector2(cos(angle), sin(angle)) * 25)

	if sprite:
		sprite.polygon = circle_points
		sprite.color = color

func select():
	is_selected = true
	scale = Vector2(1.1, 1.1)
	z_index = 10

func deselect():
	is_selected = false
	scale = Vector2(1.0, 1.0)
	z_index = 0

func _input_event(viewport, event, shape_idx):
	if event is InputEventMouseButton and event.pressed and event.button_index == MOUSE_BUTTON_LEFT:
		get_parent().piece_clicked(self)

extends Node2D

# 游戏管理器
class_name GameManager

enum GameState { MENU, PLAYING, PAUSED, LEVEL_COMPLETE, GAME_OVER }

var current_state: GameState = GameState.MENU
var current_level: int = 0
var current_ju: int = 0  # 当前局

# 关卡数据
var level_data: Dictionary = {}
var current_step: int = 0
var steps_data: Array = []

# 信号
signal state_changed(new_state)
signal level_started(level_id)
signal ju_completed(ju_id, stars)
signal step_completed(step_index)
signal show_hint(hint_text, hint_type)

func _ready():
	pass

func start_level(level_id: int):
	current_level = level_id
	current_step = 0
	current_state = GameState.PLAYING
	load_level_data(level_id)
	level_started.emit(level_id)
	state_changed.emit(current_state)

func load_level_data(level_id: int):
	# 从文件加载关卡数据
	var file_path = "res://data/levels/level_%d.json" % level_id
	if FileAccess.file_exists(file_path):
		var file = FileAccess.open(file_path, FileAccess.READ)
		var json = JSON.new()
		json.parse(file.get_as_text())
		level_data = json.get_data()
		steps_data = level_data.get("steps", [])
		file.close()

func check_move(piece, from_pos: Vector2i, to_pos: Vector2i) -> bool:
	if current_step >= steps_data.size():
		return false

	var current_step_data = steps_data[current_step]
	var targets = current_step_data.get("target", [])

	# 支持单目标或多目标
	if targets is Dictionary:
		targets = [targets]

	for target in targets:
		if to_pos.x == target.x and to_pos.y == target.y:
			return true

	return false

func on_piece_moved(piece, from_pos: Vector2i, to_pos: Vector2i):
	if check_move(piece, from_pos, to_pos):
		# 正确的移动
		current_step += 1
		step_completed.emit(current_step - 1)

		if current_step >= steps_data.size():
			# 完成本局
			complete_ju()
	else:
		# 错误的移动，显示提示
		show_error_hint()

func complete_ju():
	current_state = GameState.LEVEL_COMPLETE
	state_changed.emit(current_state)
	ju_completed.emit(current_ju, 3)  # 3星完成

func show_error_hint():
	var hints = [
		"不对哦，再想想看？",
		"这个方向走不通，试试别的？",
		"再仔细看看目标位置？",
		"不对，但没关系，再试一次！",
		"想想马走日的规则？"
	]
	show_hint.emit(hints[randi() % hints.size()], "error")

func get_current_hint() -> Dictionary:
	if current_step < steps_data.size():
		return steps_data[current_step]
	return {}

extends Node2D

@onready var board = $Board
@onready var game_manager = $GameManager
@onready var pieces_container = $Board/Pieces
@onready var hint_label = $UI/HintLabel
@onready var step_label = $UI/StepLabel

var selected_piece: Piece = null
var piece_scene = preload("res://scenes/piece.tscn")

func _ready():
	# 连接信号
	board.piece_moved.connect(_on_piece_moved)
	game_manager.step_completed.connect(_on_step_completed)
	game_manager.ju_completed.connect(_on_ju_completed)
	game_manager.show_hint.connect(_on_show_hint)

	$UI/ResetButton.pressed.connect(_on_reset)

	# 开始第一关
	start_level(1)

func start_level(level_id: int):
	game_manager.start_level(level_id)
	setup_board_from_level(level_id)
	update_ui()

func setup_board_from_level(level_id: int):
	# 清除现有棋子
	for child in pieces_container.get_children():
		child.queue_free()

	# 从关卡数据设置棋盘
	var level_file = "res://data/levels/level_%d.json" % level_id
	if FileAccess.file_exists(level_file):
		var file = FileAccess.open(level_file, FileAccess.READ)
		var json = JSON.new()
		json.parse(file.get_as_text())
		var data = json.get_data()
		file.close()

		# 创建棋子
		if data.has("pieces"):
			for piece_data in data.pieces:
				create_piece(piece_data)

		# 显示提示标记
		if data.has("steps") and data.steps.size() > 0:
			show_step_hints(data.steps[0])

func create_piece(data: Dictionary):
	var piece = piece_scene.instantiate()
	piece.piece_type = data.get("type", Piece.Type.HORSE)
	piece.side = data.get("side", Piece.Side.RED)
	piece.piece_name = data.get("name", "马")

	var pos = Vector2i(data.x, data.y)
	board.place_piece(piece, pos)
	pieces_container.add_child(piece)

func show_step_hints(step_data: Dictionary):
	# 显示当前步骤的提示
	var hint_type = step_data.get("hintType", "precise")
	var hint_text = step_data.get("hintText", "")

	if hint_label:
		hint_label.text = hint_text

func piece_clicked(piece: Piece):
	if selected_piece == piece:
		piece.deselect()
		selected_piece = null
		return

	if selected_piece:
		# 尝试移动
		var target_pos = piece.board_pos
		var from_pos = selected_piece.board_pos

		if game_manager.check_move(selected_piece, from_pos, target_pos):
			# 吃子移动
			board.move_piece(from_pos, target_pos)
			game_manager.on_piece_moved(selected_piece, from_pos, target_pos)
		else:
			# 无效移动，重新选择
			selected_piece.deselect()
			piece.select()
			selected_piece = piece
	else:
		# 选择棋子
		if piece.side == Piece.Side.RED:  # 只能选红方
			piece.select()
			selected_piece = piece

func _input(event):
	if event is InputEventMouseButton and event.pressed and event.button_index == MOUSE_BUTTON_LEFT:
		if selected_piece:
			# 检查是否点击了棋盘上的空位
			var click_pos = get_global_mouse_position()
			var grid_pos = board.world_to_grid(click_pos)

			if board.is_valid_position(grid_pos):
				var target_piece = board.get_piece_at(grid_pos)
				if target_piece == null:
					# 移动到空位
					var from_pos = selected_piece.board_pos
					if game_manager.check_move(selected_piece, from_pos, grid_pos):
						board.move_piece(from_pos, grid_pos)
						game_manager.on_piece_moved(selected_piece, from_pos, grid_pos)
						selected_piece.deselect()
						selected_piece = null

func _on_piece_moved(from_pos, to_pos, piece):
	update_ui()

func _on_step_completed(step_index):
	update_ui()
	# 显示下一步提示
	var hint_data = game_manager.get_current_hint()
	if hint_data:
		show_step_hints(hint_data)

func _on_ju_completed(ju_id, stars):
	hint_label.text = "🎉 泰裤辣！本局完成！"
	# 显示结算界面（后续实现）

func _on_show_hint(hint_text, hint_type):
	hint_label.text = hint_text

func _on_reset():
	selected_piece = null
	start_level(game_manager.current_level)

func update_ui():
	if step_label:
		step_label.text = "步骤: %d/%d" % [game_manager.current_step, game_manager.steps_data.size()]

