class_name Piece
extends Node2D

enum PieceType { HORSE, CHARIOT, CANNON, ELEPHANT, ADVISOR, GENERAL, SOLDIER }
enum PieceSide { RED, BLACK }

@export var piece_type: PieceType = PieceType.HORSE
@export var piece_side: PieceSide = PieceSide.RED
@export var piece_name: String = "马"

var board_pos: Vector2i = Vector2i.ZERO
var is_selected: bool = false

@onready var sprite: Polygon2D = $Polygon2D

func _ready():
	_draw_piece()

func _draw_piece():
	# 使用 Polygon2D 绘制简单棋子
	# 实际项目中替换为图片
	var color = Color.RED if side == Side.RED else Color.BLACK

	# 绘制圆形棋子底
	var circle_points = []
	for i in range(32):
		var angle = i * PI / 16
		circle_points.append(Vector2(cos(angle), sin(angle)) * 25)

	if sprite:
		sprite.polygon = circle_points
		sprite.color = color

func select():
	is_selected = true
	scale = Vector2(1.1, 1.1)
	z_index = 10

func deselect():
	is_selected = false
	scale = Vector2(1.0, 1.0)
	z_index = 0

func _input_event(viewport, event, shape_idx):
	if event is InputEventMouseButton and event.pressed and event.button_index == MOUSE_BUTTON_LEFT:
		get_parent().piece_clicked(self)

